1	// WORKSTATE 상태 전이의 유일한 writer. 낙관적 동시성·멱등 전이-ID·canonical 검증·전이 그래프·WP-REGISTRY 검사를 강제한다.
2	using System.Security.Cryptography;
3	using System.Text;
4	using System.Text.Encodings.Web;
5	using System.Text.Json;
6	using System.Text.Json.Nodes;
7	using System.Text.RegularExpressions;
8	
9	internal static class StateApplierCli
10	{
11	    private static readonly JsonSerializerOptions WriteOptions = new()
12	    {
13	        WriteIndented = true,
14	        Encoder = JavaScriptEncoder.UnsafeRelaxedJsonEscaping,
15	    };
16	
17	    private static readonly HashSet<string> ValidStatuses = new(StringComparer.OrdinalIgnoreCase)
18	    {
19	        "waiting", "in_progress", "verifying", "completed", "blocked",
20	    };
21	
22	    // 허용 전이 화이트리스트 — 이 표 밖의 전이는 전부 거부(completed는 terminal).
23	    private static readonly Dictionary<string, HashSet<string>> AllowedTransitions = new(StringComparer.OrdinalIgnoreCase)
24	    {
25	        ["waiting"] = new(StringComparer.OrdinalIgnoreCase) { "in_progress", "blocked" },
26	        ["in_progress"] = new(StringComparer.OrdinalIgnoreCase) { "verifying", "blocked", "waiting" },
27	        ["verifying"] = new(StringComparer.OrdinalIgnoreCase) { "completed", "in_progress", "blocked" },
28	        ["blocked"] = new(StringComparer.OrdinalIgnoreCase) { "waiting", "in_progress", "verifying" },
29	        ["completed"] = new(StringComparer.OrdinalIgnoreCase) { },
30	    };
31	
32	    // nextActions 필수 status 목록(completed 제외).
33	    private static readonly HashSet<string> NextActionsRequired = new(StringComparer.OrdinalIgnoreCase)
34	    {
35	        "waiting", "in_progress", "verifying", "blocked",
36	    };
37	
38	    // CLI 인수를 담는 불변 레코드.
39	    private record ApplierOptions(
40	        string TransitionId,
41	        string ExpectedSha256,
42	        string RequestPath,
43	        string? VerdictPath,
44	        string? HumanDecisionPath,
45	        string? Root,    // 지정 시 이 경로를 저장소 루트로 사용한다.
46	        bool DryRun);    // true면 검증만 하고 아무것도 쓰지 않는다.
47	
48	    // state-transition 진입점. exit 0=성공, 1=검증 실패, 2=치명 오류.
49	    internal static int Run(string[] args)
50	    {
51	        var opts = ParseArgs(args);
52	        if (opts is null)
53	        {
54	            Console.Error.WriteLine("{\"error\":\"--transition-id, --expected-workstate-sha256, --request 가 모두 필요합니다\"}");
55	            return 2;
56	        }
57	
58	        try
59	        {
60	            var root = string.IsNullOrWhiteSpace(opts.Root) ? GitTools.FindRepoRoot() : opts.Root;
61	            var workstatePath = Path.Combine(root, "docs", "handoff", "WORKSTATE.json");
62	            if (!File.Exists(workstatePath))
63	            {
64	                WriteError("WORKSTATE.json not found");
65	                return 2;
66	            }
67	
68	            var raw = File.ReadAllText(workstatePath, new UTF8Encoding(false));
69	            var workstate = JsonNode.Parse(raw)?.AsObject();
70	            if (workstate is null)
71	            {
72	                WriteError("WORKSTATE.json is not a valid JSON object");
73	                return 2;
74	            }
75	
76	            // Step 1: 낙관적 동시성 — sha256 불일치 시 쓰지 않는다.
77	            var currentSha = ComputeSha256(raw);
78	            if (!string.Equals(currentSha, opts.ExpectedSha256, StringComparison.OrdinalIgnoreCase))
79	                return Fail(1, opts.TransitionId, "sha256-mismatch",
80	                    $"expected={opts.ExpectedSha256[..Math.Min(16, opts.ExpectedSha256.Length)]}... " +
81	                    $"actual={currentSha[..Math.Min(16, currentSha.Length)]}...");
82	
83	            // Step 2: 멱등 — 같은 transition-id는 한 번만 적용한다.
84	            if (IsAlreadyApplied(workstate, opts.TransitionId))
85	                return ReportIdempotent(opts.TransitionId);
86	
87	            var logPath = Path.Combine(root, "docs", "handoff", "WORKSTATE.applier-log.jsonl");
88	            return ApplyAndVerify(workstatePath, logPath, workstate, opts, GitTools.FindRepoRoot());
89	        }
90	        catch (Exception ex)
91	        {
92	            Console.Error.WriteLine($"{{\"error\":\"state-transition 실패: {ex.Message}\"}}");
93	            return 2;
94	        }
95	    }
96	
97	    // request 검증, candidate 구성, (dry-run이 아니면) atomic replace·post-apply를 순서대로 실행한다.
98	    private static int ApplyAndVerify(
99	        string workstatePath, string logPath, JsonObject workstate,
100	        ApplierOptions opts, string actualRoot)
101	    {
102	        if (!File.Exists(opts.RequestPath))
103	        {
104	            WriteError($"request file not found: {opts.RequestPath}");
105	            return 2;
106	        }
107	        var request = JsonNode.Parse(File.ReadAllText(opts.RequestPath))?.AsObject();
108	        if (request is null) { WriteError("request JSON은 JSON 객체여야 한다"); return 2; }
109	
110	        var validErr = ValidateRequest(request, opts, workstate, actualRoot);
111	        if (validErr is not null)
112	            return Fail(1, opts.TransitionId, "validation-failed", validErr);
113	
114	        var candidate = BuildCandidate(workstate, request, opts);
115	        if (opts.DryRun) return ApplyDryRun(workstate, candidate, opts, actualRoot);
116	
117	        var tmpPath = workstatePath + ".stateapplier.tmp";
118	        File.WriteAllText(tmpPath, candidate.ToJsonString(WriteOptions), new UTF8Encoding(false));
119	
120	        var candidateCheck = JsonNode.Parse(File.ReadAllText(tmpPath))?.AsObject();
121	        var recheckErr = candidateCheck is null ? "임시 파일 파싱 실패" : ValidateCandidate(candidateCheck, actualRoot);
122	        if (recheckErr is not null) { File.Delete(tmpPath); return Fail(1, opts.TransitionId, "candidate-invalid", recheckErr); }
123	
124	        File.Move(tmpPath, workstatePath, overwrite: true);
125	
126	        // 커스텀 루트에서는 projection·handoff-integrity를 건너뛴다(GitTools로 실 저장소를 찾으므로 사본에 의미 없음).
127	        if (string.IsNullOrWhiteSpace(opts.Root))
128	        {
129	            var postExit = RunPostApply(logPath, opts);
130	            if (postExit != 0) return postExit;
131	        }
132	
133	        var newSha = ComputeSha256(File.ReadAllText(workstatePath, new UTF8Encoding(false)));
134	        AppendApplierLog(logPath, opts.TransitionId, "ok", 0);
135	        Console.WriteLine(new JsonObject
136	        {
137	            ["ok"] = true,
138	            ["transitionId"] = opts.TransitionId,
139	            ["previousStatus"] = workstate["status"]?.ToString(),
140	            ["newStatus"] = candidate["status"]?.ToString(),
141	            ["workstateSha256"] = newSha,
142	        }.ToJsonString(WriteOptions));
143	        return 0;
144	    }
145	
146	    // dry-run 모드: candidate를 검증하고 결과를 출력하지만 아무것도 쓰지 않는다.
147	    private static int ApplyDryRun(JsonObject workstate, JsonObject candidate, ApplierOptions opts, string actualRoot)
148	    {
149	        var err = ValidateCandidate(candidate, actualRoot);
150	        if (err is not null) return Fail(1, opts.TransitionId, "candidate-invalid", err);
151	        Console.WriteLine(new JsonObject
152	        {
153	            ["ok"] = true,
154	            ["dryRun"] = true,
155	            ["transitionId"] = opts.TransitionId,
156	            ["previousStatus"] = workstate["status"]?.ToString(),
157	            ["newStatus"] = candidate["status"]?.ToString(),
158	        }.ToJsonString(WriteOptions));
159	        return 0;
160	    }
161	
162	    // projection과 handoff-integrity를 실행하고 실패 시 applier-log에 기록하고 exit code를 반환한다.
163	    private static int RunPostApply(string logPath, ApplierOptions opts)
164	    {
165	        var projExit = ProjectionCli.Run(["projection"]);
166	        if (projExit != 0)
167	        {
168	            AppendApplierLog(logPath, opts.TransitionId, "projection-failed", projExit);
169	            Console.Error.WriteLine(PostApplyError(opts.TransitionId, "projection-failed", projExit, true, false));
170	            return 1;
171	        }
172	        var intExit = HandoffIntegrityCli.Run(["handoff-integrity"]);
173	        if (intExit != 0)
174	        {
175	            AppendApplierLog(logPath, opts.TransitionId, $"handoff-integrity-failed exit={intExit}", intExit);
176	            Console.Error.WriteLine(PostApplyError(opts.TransitionId, $"handoff-integrity exit={intExit}", intExit, true, true));
177	            return 1;
178	        }
179	        return 0;
180	    }
181	
182	    // request JSON의 canonical ID 패턴, status enum, 사전조건(blocked/nextActions/verdict/human-decision)을 검증한다.
183	    private static string? ValidateRequest(JsonObject request, ApplierOptions opts, JsonObject current, string root)
184	    {
185	        if (request["phaseId"] is JsonNode ph && !Regex.IsMatch(ph.ToString(), @"^P\d{2,}$"))
186	            return $"phaseId '{ph}'는 canonical 형식(P00, P01 …)이 아닙니다";
187	
188	        if (request["wpId"] is JsonNode wp && !Regex.IsMatch(wp.ToString(), @"^WP-\d{2,}$"))
189	            return $"wpId '{wp}'는 canonical 형식(WP-00 …)이 아닙니다";
190	
191	        if (request["diId"] is JsonNode di && !Regex.IsMatch(di.ToString(), @"^DI-\d{2}-\d{2,}$"))
192	            return $"diId '{di}'는 canonical 형식(DI-00-05 …)이 아닙니다";
193	
194	        var newStatus = request["status"]?.ToString() ?? current["status"]?.ToString() ?? "";
195	        if (!ValidStatuses.Contains(newStatus))
196	            return $"status '{newStatus}'는 허용 목록(waiting|in_progress|verifying|completed|blocked)에 없습니다";
197	
198	        // Rule NEW: 허용 전이 그래프 검사 — 역방향 및 비허용 전이를 exit 1로 차단.
199	        var currentStatus = current["status"]?.ToString() ?? "";
200	        if (!string.Equals(currentStatus, newStatus, StringComparison.OrdinalIgnoreCase))
201	        {
202	            if (string.Equals(currentStatus, "completed", StringComparison.OrdinalIgnoreCase))
203	            {
204	                // completed는 terminal — 사람 결재(human-decision approved:true) 없으면 차단.
205	                var completedErr = ValidateHumanDecision(opts.HumanDecisionPath,
206	                    $"completed 상태 전이({currentStatus} → {newStatus})");
207	                if (completedErr is not null) return completedErr;
208	            }
209	            else if (AllowedTransitions.TryGetValue(currentStatus, out var allowed) && !allowed.Contains(newStatus))
210	            {
211	                var allowedStr = allowed.Count > 0 ? string.Join(", ", allowed) : "없음(terminal)";
212	                return $"status 전이 {currentStatus} → {newStatus}는 허용되지 않습니다(허용: {allowedStr})";
213	            }
214	        }
215	
216	        var newBlockers = request["blockers"] as JsonArray ?? current["blockers"] as JsonArray ?? new JsonArray();
217	        var newNext = request["nextActions"] as JsonArray ?? current["nextActions"] as JsonArray ?? new JsonArray();
218	
219	        // Rule 4: blocked → blockers 비어있으면 실패.
220	        if (string.Equals(newStatus, "blocked", StringComparison.OrdinalIgnoreCase) && newBlockers.Count == 0)
221	            return "status=blocked인데 blockers가 비어있습니다";
222	
223	        // Rule 5: non-terminal → nextActions 비어있으면 실패 (독립 재개 FAIL 방어선).
224	        if (NextActionsRequired.Contains(newStatus) && newNext.Count == 0)
225	            return $"status={newStatus}인데 nextActions가 비어있습니다 — 독립 재개가 실패하는 지점입니다";
226	
227	        // Rule 6: completed → 독립 검증 PASS 필수.
228	        if (string.Equals(newStatus, "completed", StringComparison.OrdinalIgnoreCase))
229	        {
230	            var verdictErr = ValidateVerdict(opts.VerdictPath);
231	            if (verdictErr is not null) return verdictErr;
232	        }
233	
234	        // Rule 7: Phase gate → 사람 결정 필수.
235	        var curPhase = current["phaseId"]?.ToString();
236	        var newPhase = request["phaseId"]?.ToString();
237	        if (newPhase is not null && !string.Equals(newPhase, curPhase, StringComparison.OrdinalIgnoreCase))
238	        {
239	            var gateErr = ValidateHumanDecision(opts.HumanDecisionPath, $"Phase 전이({curPhase} → {newPhase})");
240	            if (gateErr is not null) return gateErr;
241	        }
242	
243	        return null;
244	    }
245	
246	    // verdict 파일이 verificationPassed=true, exitCode=0인지 검증한다.
247	    private static string? ValidateVerdict(string? verdictPath)
248	    {
249	        if (string.IsNullOrWhiteSpace(verdictPath))
250	            return "status=completed 전이에는 --verdict 파일이 필요합니다";
251	        if (!File.Exists(verdictPath))
252	            return $"verdict file not found: {verdictPath}";
253	        var v = JsonNode.Parse(File.ReadAllText(verdictPath))?.AsObject();
254	        if (v is null) return "verdict JSON이 유효하지 않습니다";
255	        var passed = v["verificationPassed"]?.GetValue<bool>() ?? false;
256	        var exitCode = v["exitCode"]?.GetValue<int>() ?? -1;
257	        return (!passed || exitCode != 0) ? $"verdict: verificationPassed={passed}, exitCode={exitCode} — PASS가 아닙니다" : null;
258	    }
259	
260	    // human-decision 파일이 approved=true인지 검증한다. context는 오류 메시지에 포함된다.
261	    private static string? ValidateHumanDecision(string? decPath, string context)
262	    {
263	        if (string.IsNullOrWhiteSpace(decPath))
264	            return $"{context}에는 --human-decision 파일이 필요합니다";
265	        if (!File.Exists(decPath))
266	            return $"human-decision file not found: {decPath}";
267	        var d = JsonNode.Parse(File.ReadAllText(decPath))?.AsObject();
268	        if (d is null) return "human-decision JSON이 유효하지 않습니다";
269	        var approved = d["approved"]?.GetValue<bool>() ?? false;
270	        return !approved ? $"{context}가 사람에게 승인되지 않았습니다(approved={approved})" : null;
271	    }
272	
273	    // request 필드를 current WORKSTATE에 병합해 candidate를 만들고 appliedTransitions에 기록한다.
274	    private static JsonObject BuildCandidate(JsonObject current, JsonObject request, ApplierOptions opts)
275	    {
276	        var candidate = JsonNode.Parse(current.ToJsonString(WriteOptions))!.AsObject()!;
277	
278	        foreach (var key in new[] { "phaseId", "wpId", "diId", "status", "blockers", "nextActions", "updatedBy", "notes" })
279	        {
280	            if (request[key] is JsonNode node)
281	                candidate[key] = node.DeepClone();
282	        }
283	
284	        candidate["updatedAt"] = DateTime.UtcNow.ToString("yyyy-MM-dd");
285	
286	        if (candidate["appliedTransitions"] is not JsonArray applied)
287	        {
288	            applied = new JsonArray();
289	            candidate["appliedTransitions"] = applied;
290	        }
291	
292	        applied.Add(new JsonObject
293	        {
294	            ["id"] = opts.TransitionId,
295	            ["appliedAt"] = DateTime.UtcNow.ToString("o"),
296	        });
297	
298	        return candidate;
299	    }
300	
301	    // candidate WORKSTATE의 사후 조건(status enum, blocked→blockers, non-terminal→nextActions, canonical ID 패턴, WP-REGISTRY 등록 여부)을 검증한다.
302	    private static string? ValidateCandidate(JsonObject candidate, string root)
303	    {
304	        var status = candidate["status"]?.ToString() ?? "";
305	        if (!ValidStatuses.Contains(status))
306	            return $"candidate status '{status}'가 유효하지 않습니다";
307	
308	        var blockers = candidate["blockers"] as JsonArray;
309	        if (string.Equals(status, "blocked", StringComparison.OrdinalIgnoreCase) && (blockers is null || blockers.Count == 0))
310	            return "candidate: status=blocked인데 blockers가 비어있습니다";
311	
312	        var nextActions = candidate["nextActions"] as JsonArray;
313	        if (NextActionsRequired.Contains(status) && (nextActions is null || nextActions.Count == 0))
314	            return $"candidate: status={status}인데 nextActions가 비어있습니다";
315	
316	        // canonical 패턴 검사 — 정지 상태(at rest)에서도 강제한다(요청에 없어 상속된 값 포함).
317	        if (candidate["phaseId"] is JsonNode ph && !Regex.IsMatch(ph.ToString(), @"^P\d{2,}$"))
318	            return $"candidate phaseId '{ph}'는 canonical 형식(P00, P01 …)이 아닙니다";
319	
320	        if (candidate["wpId"] is JsonNode wp && !Regex.IsMatch(wp.ToString(), @"^WP-\d{2,}$"))
321	            return $"candidate wpId '{wp}'는 canonical 형식(WP-00 …)이 아닙니다";
322	
323	        if (candidate["diId"] is JsonNode di && !Regex.IsMatch(di.ToString(), @"^DI-\d{2}-\d{2,}$"))
324	            return $"candidate diId '{di}'는 canonical 형식(DI-00-05 …)이 아닙니다";
325	
326	        // WP-REGISTRY 검사 — wpId가 등록된 WP인지 확인한다.
327	        var wpId = candidate["wpId"]?.ToString();
328	        if (!string.IsNullOrWhiteSpace(wpId))
329	        {
330	            var registryErr = ValidateWpRegistry(root, wpId);
331	            if (registryErr is not null) return registryErr;
332	        }
333	
334	        return null;
335	    }
336	
337	    // wpId가 WP-REGISTRY.json에 등록되어 있는지 검사한다. 없으면 오류 메시지를 반환한다.
338	    private static string? ValidateWpRegistry(string root, string wpId)
339	    {
340	        var registryPath = Path.Combine(root, "docs", "handoff", "WP-REGISTRY.json");
341	        if (!File.Exists(registryPath))
342	            return "WP-REGISTRY.json not found — WP 등록표가 없습니다";
343	
344	        var reg = JsonNode.Parse(File.ReadAllText(registryPath))?.AsObject();
345	        if (reg is null) return "WP-REGISTRY.json이 유효한 JSON 객체가 아닙니다";
346	
347	        var wps = reg["wps"] as JsonArray;
348	        if (wps is null) return "WP-REGISTRY.json에 'wps' 배열이 없습니다";
349	
350	        var exists = wps.OfType<JsonObject>().Any(w =>
351	            string.Equals(w["wpId"]?.ToString(), wpId, StringComparison.OrdinalIgnoreCase));
352	
353	        return exists ? null : $"wpId '{wpId}'가 WP-REGISTRY.json에 등록되지 않았습니다 — WP 추가는 사람 결재입니다";
354	    }
355	
356	    // CLI 인수를 파싱한다. 필수 인수(transition-id·expected-workstate-sha256·request)가 없으면 null 반환.
357	    // --root <경로>: 저장소 루트를 지정한다(사본 시험용). --dry-run: 검증만 하고 아무것도 쓰지 않는다.
358	    private static ApplierOptions? ParseArgs(string[] args)
359	    {
360	        var map = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
361	        var dryRun = false;
362	        for (var i = 1; i < args.Length; i++)
363	        {
364	            if (string.Equals(args[i], "--dry-run", StringComparison.OrdinalIgnoreCase))
365	            {
366	                dryRun = true;
367	                continue;
368	            }
369	            if (args[i].StartsWith("--", StringComparison.Ordinal) && i + 1 < args.Length)
370	            {
371	                map[args[i][2..]] = args[i + 1];
372	                i++;
373	            }
374	        }
375	
376	        if (!map.TryGetValue("transition-id", out var tid) || string.IsNullOrWhiteSpace(tid)) return null;
377	        if (!map.TryGetValue("expected-workstate-sha256", out var sha) || string.IsNullOrWhiteSpace(sha)) return null;
378	        if (!map.TryGetValue("request", out var req) || string.IsNullOrWhiteSpace(req)) return null;
379	
380	        map.TryGetValue("verdict", out var verdict);
381	        map.TryGetValue("human-decision", out var humanDec);
382	        map.TryGetValue("root", out var root);
383	        return new ApplierOptions(tid, sha, req, verdict, humanDec, root, dryRun);
384	    }
385	
386	    // appliedTransitions에서 transition-id 중복 여부를 확인한다.
387	    private static bool IsAlreadyApplied(JsonObject workstate, string transitionId)
388	    {
389	        var applied = workstate["appliedTransitions"] as JsonArray;
390	        if (applied is null) return false;
391	        return applied.OfType<JsonObject>().Any(o =>
392	            string.Equals(o["id"]?.ToString(), transitionId, StringComparison.OrdinalIgnoreCase));
393	    }
394	
395	    // 이미 적용된 transition-id에 대한 idempotent 응답을 출력하고 0을 반환한다.
396	    private static int ReportIdempotent(string transitionId)
397	    {
398	        Console.WriteLine(new JsonObject
399	        {
400	            ["ok"] = true,
401	            ["transitionId"] = transitionId,
402	            ["idempotent"] = true,
403	            ["note"] = "이 transition-id는 이미 적용됐다 — 상태를 바꾸지 않는다",
404	        }.ToJsonString(WriteOptions));
405	        return 0;
406	    }
407	
408	    // post-apply 단계 실패 메시지를 JSON 문자열로 만든다.
409	    private static string PostApplyError(string tid, string failure, int exitCode, bool wsApplied, bool projApplied)
410	    {
411	        var note = projApplied
412	            ? "WORKSTATE와 projection은 갱신됐으나 handoff-integrity가 실패했다"
413	            : "WORKSTATE는 갱신됐으나 projection이 실패했다 — projection을 수동으로 재실행하라";
414	        return new JsonObject
415	        {
416	            ["transitionId"] = tid,
417	            ["phase"] = "post-apply",
418	            ["failure"] = failure,
419	            ["exitCode"] = exitCode,
420	            ["workstateApplied"] = wsApplied,
421	            ["projectionApplied"] = projApplied,
422	            ["note"] = note,
423	        }.ToJsonString();
424	    }
425	
426	    // 전이 결과를 WORKSTATE.applier-log.jsonl에 한 줄 추가한다(append-only).
427	    private static void AppendApplierLog(string logPath, string transitionId, string result, int exitCode)
428	    {
429	        var entry = new JsonObject
430	        {
431	            ["transitionId"] = transitionId,
432	            ["result"] = result,
433	            ["exitCode"] = exitCode,
434	            ["at"] = DateTime.UtcNow.ToString("o"),
435	        };
436	        File.AppendAllText(logPath, entry.ToJsonString() + "\n", new UTF8Encoding(false));
437	    }
